const componentApiByModuleName = new Map(
  componentApi.components.map((c) => [c.moduleName, c]),
);

[theme="white"] .token.tag,
[theme="g10"] .token.tag,
[theme="white"] .token.operator,
[theme="g10"] .token.operator {
  color: #0043ce; /* blue 70 */
}

[theme="white"] .token.token.language-javascript,
[theme="g10"] .token.token.language-javascript,
[theme="white"] .token.attr-value,
[theme="g10"] .token.attr-value {
  color: #8a3ffc; /* purple 60 */
}

[theme="white"] .token.script .token.language-javascript,
[theme="g10"] .token.script .token.language-javascript {
  color: #005d5d; /* teal 70 */
}

if (validThemes.includes(theme)) {
  document.documentElement.setAttribute("theme", theme);
  document.documentElement.style.setProperty(
    "color-scheme",
    ["white", "g10"].includes(theme) ? "light" : "dark",
  );
}

const headers = [
  { key: "name", value: "Name" },
  { key: "port", value: "Port" },
  { key: "rule", value: "Rule" },
  { key: "overflow", empty: true, width: "72px" },
];

if (checkedNodes.has(nodeId)) {
  checkedNodes.delete(nodeId);
} else {
  checkedNodes.add(nodeId);
}

return {
  update(text) {
    if (document.activeElement !== element) {
      element.textContent = text;
    }
  },
};

const grammarKey = raw
    ? (MDSVEX_LANG_ALIASES[raw as keyof typeof MDSVEX_LANG_ALIASES] ?? raw)
    : "";

if (size !== undefined)
    // svelte-ignore reactive_declaration_non_reactive_property
    dispatch("change", { size, breakpointValue: breakpoints[size] });

setContext("carbon:CheckboxGroup", {
  selectedValues,
  groupName: readOnly(groupName),
  groupRequired: readOnly(groupRequired),
  readonly: readOnly(groupReadonly),
  update,
});

if (Array.isArray(a) && Array.isArray(b)) {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) {
    // Pass the stack to handle nested arrays and prevent infinite recursion.
    if (!deepEqual(a[i], b[i], stack)) return false;
  }
  return true;
}

selectAll =
    selectableRowIds.length > 0 &&
    selectedRowIds.length === selectableRowIds.length;

if (ctxToolbar?.overflowVisible) {
  unsubscribeOverflow = ctxToolbar.overflowVisible.subscribe((value) => {
    overflowVisible = value;
  });
}

if (ctx?.batchActionsActive) {
  unsubscribe = ctx.batchActionsActive.subscribe((value) => {
    batchActionsActive = value;
  });
}

if (lastAppliedOptions[optionKey] !== value) {
  calendar.set(optionKey, appliedValue);
  lastAppliedOptions[optionKey] = value;
}

if (calendar) {
  calendar.set("clickOpens", !$readonlyAny);
  if ($readonlyAny && calendar.isOpen) calendar.close();
}

const calendarHeight = Array.prototype.reduce.call(
  calendarContainer.children,
  (/** @type {number} */ acc, /** @type {HTMLElement} */ child) =>
    acc + child.offsetHeight,
  0,
);

if (rightMost) {
  calendarContainer.style.left = "auto";
  calendarContainer.style.right = `${window.innerWidth - inputBounds.right}px`;
} else {
  calendarContainer.style.left = `${left}px`;
  calendarContainer.style.right = "auto";
}

for (let index = 0; index < items.length; index++) {
  itemsById.set(items[index].id, items[index]);
}

const defaultTranslations = {
  [translationIds.close]: "Close menu",
  [translationIds.open]: "Open menu",
};

const defaultTranslations = {
  [translationIds.clearAll]: "Clear all selected items",
  [translationIds.clearSelection]: "Clear selected item",
};

const shouldContinue = dispatch(
  "close",
  { timeout: closeFromTimeout === true },
  { cancelable: true },
);

effectiveInvalid =
    (() => {
      if (invalid) return true;
      if (customValid === false) return true;
      if (customValid === true) return false;
      return autoInvalid;
    })() && !readonly;
